 1	import React, { Dispatch, FC, SetStateAction } from 'react';
 2	
 3	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 4	import {
 5	  Button,
 6	  ButtonVariant,
 7	  Checkbox,
 8	  Flex,
 9	  FormGroup,
10	  Popover,
11	  PopoverPosition,
12	  TextInput,
13	} from '@patternfly/react-core';
14	import { HelpIcon } from '@patternfly/react-icons';
15	
16	type CheckupsNetworkFormLatencyProps = {
17	  desiredLatency: string;
18	  isDesiredLatency: boolean;
19	  setDesiredLatency: Dispatch<SetStateAction<string>>;
20	  setIsDesiredLatency: Dispatch<SetStateAction<boolean>>;
21	};
22	
23	const CheckupsNetworkFormLatency: FC<CheckupsNetworkFormLatencyProps> = ({
24	  desiredLatency,
25	  isDesiredLatency,
26	  setDesiredLatency,
27	  setIsDesiredLatency,
28	}) => {
29	  const { t } = useKubevirtTranslation();
30	  return (
31	    <FormGroup fieldId="desired-latency">
32	      <Flex>
33	        <Checkbox
34	          id="desired-latency"
35	          isChecked={isDesiredLatency}
36	          label={t('Set maximum desired latency (milliseconds)')}
37	          name="desired-latency"
38	          onChange={(_event, check) => setIsDesiredLatency(check)}
39	        />
40	        <Popover
41	          bodyContent={t('If the measured latency exceeds this value, the checkup fails.')}
42	          position={PopoverPosition.right}
43	        >
44	          <Button variant={ButtonVariant.plain}>
45	            <HelpIcon />
46	          </Button>
47	        </Popover>
48	      </Flex>
49	
50	      {isDesiredLatency && (
51	        <TextInput
52	          className="CheckupsNetworkForm--main__number-input"
53	          id="desired-latency-value"
54	          name="desired-latency-value"
55	          onChange={(_event, value) => setDesiredLatency(value)}
56	          type="number"
57	          value={desiredLatency}
58	        />
59	      )}
60	    </FormGroup>
61	  );
62	};
63	
64	export default CheckupsNetworkFormLatency;

